/**
 * Auto-updates products.ts with Lemon Squeezy checkout URLs.
 * Run after create-ls-products.mjs has generated ls-product-ids.json.
 *
 * Usage:
 *   node scripts/update-products-ts.mjs
 */

import { readFile, writeFile } from "fs/promises";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");

async function main() {
  // Load the LS product IDs generated by create-ls-products.mjs
  const idsPath = join(__dirname, "ls-product-ids.json");
  const products = JSON.parse(await readFile(idsPath, "utf8"));

  // Load products.ts
  const tsPath = join(ROOT, "src/data/products.ts");
  let ts = await readFile(tsPath, "utf8");

  let updatedCount = 0;
  const notFound = [];

  for (const { name, checkoutUrl } of products) {
    // Find the product block by name and replace its lemonSqueezyUrl
    // Pattern: find name: "Product Name", then find the nearest lemonSqueezyUrl: "#" after it
    const namePattern = name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const regex = new RegExp(
      `(name:\\s*"${namePattern}"[\\s\\S]{0,500}?lemonSqueezyUrl:\\s*)"#"`,
      "m"
    );

    if (regex.test(ts)) {
      ts = ts.replace(regex, `$1"${checkoutUrl}"`);
      updatedCount++;
      console.log(`Updated: ${name}`);
    } else {
      notFound.push(name);
      console.log(`NOT FOUND in products.ts: ${name}`);
    }
  }

  // Write updated products.ts
  await writeFile(tsPath, ts, "utf8");

  console.log(`\nUpdated ${updatedCount}/${products.length} products in products.ts`);

  if (notFound.length > 0) {
    console.log(`\nNot found (check name spelling):`);
    notFound.forEach((n) => console.log(`  - ${n}`));
  }

  console.log("\nDone. Commit and deploy to go live.");
}

main().catch(console.error);
